// Extended dhātu list — composes the top-25 (in dhatus.js) with three
// per-frequency-range part files generated by parallel agents to reach
// the Khoomeik top-192 (~86.1% verb-token coverage).
//
// Used by decodeHelper.js classifyByStem for vocabulary-backed verb
// detection — the more dhātus we have, the more verbs the engine can
// confirm on top of the regex-based pass.
//
// Each part file exports DHATUS_PART_N: array of dhātu entries with
// at minimum {id, devanagari, presentStem, pada, gana} — enough for
// the cross-check; richer fields (futureStem, perfect3sg, gitaOccurrences)
// are filled in only on the top-25 today.
//
// Coverage status:
//   - dhatus.js DHATUS:        ranks 1–25   (rich data)
//   - _dhatus_part2.js:        ranks 26–100  (75 entries)
//   - _dhatus_part3.js:        ranks 101–150 (50 entries)
//   - _dhatus_part4.js:        ranks 151–192 (42 entries)
// Total: 192 dhātus (~86.1% verb-token coverage of the DCS corpus).
//
// Audit and tighten the bulk-generated entries' presentStems over time.

import { DHATUS_TOP25 } from './dhatus.js';
import { DHATUS_PART_2 } from './_dhatus_part2.js';
import { DHATUS_PART_3 } from './_dhatus_part3.js';
import { DHATUS_PART_4 } from './_dhatus_part4.js';
import { DHATUS_EXTRA } from './_dhatus_extra.js';

// Hand-added dhātus the bulk-generated parts missed but appear in the
// Gītā corpus. √या ("go") is a particularly egregious miss — it's one
// of the most common verbs in the text (यान्ति, यासि, यान्ति, etc.).
const DHATUS_PATCH = [
  {
    id: 'ya',
    devanagari: 'या',
    iast: 'yā',
    meanings: ['go', 'reach'],
    gana: 2,
    pada: 'P',
    thematic: false,
    frequencyRank: null,
    presentStem: 'या',
    isSuppletive: false,
  },
  {
    id: 'arh',
    devanagari: 'अर्ह्',
    iast: 'arh',
    meanings: ['be able', 'deserve', 'ought'],
    gana: 1,
    pada: 'P',
    thematic: true,
    frequencyRank: null,
    presentStem: 'अर्ह',
    isSuppletive: false,
  },
  {
    id: 'shru',
    devanagari: 'श्रु',
    iast: 'śru',
    meanings: ['hear', 'listen'],
    gana: 5,
    pada: 'P',
    thematic: false,
    frequencyRank: null,
    presentStem: 'शृणु',
    isSuppletive: true,
  },
  {
    id: 'as',
    devanagari: 'अस्',
    iast: 'as',
    meanings: ['be'],
    gana: 2,
    pada: 'P',
    thematic: false,
    frequencyRank: null,
    presentStem: 'अस्',
    isSuppletive: true,
    // The 2sg of √अस् is irregular: असि (just stem + i, not stem + सि).
    // Conjugator overrides handle the full paradigm; here we just expose
    // the stem so classifyByStem at least sees the root exists.
  },
];

// Dedup on merge — the 8 agents that wrote the part files independently
// re-listed many common dhātus (33 duplicate ids, 44 duplicate devanagari
// forms across parts). Top-25 (rich data: futureStem, gitaOccurrences,
// etc.) wins on collision; among parts 2-4 the first occurrence wins
// (lower frequencyRank). Final list is ~192 unique dhātus + the PATCH
// additions for high-frequency verbs the agents missed.
function mergeDhatus(...lists) {
  const seenById = new Set();
  const seenByForm = new Set(); // dedupes by devanagari + gana + pada
  const merged = [];
  for (const list of lists) {
    for (const d of list) {
      const formKey = `${d.devanagari}|${d.gana}|${d.pada}`;
      if (seenById.has(d.id) || seenByForm.has(formKey)) continue;
      seenById.add(d.id);
      seenByForm.add(formKey);
      merged.push(d);
    }
  }
  return merged;
}

export const DHATUS_EXTENDED = mergeDhatus(
  DHATUS_TOP25,
  DHATUS_PART_2,
  DHATUS_PART_3,
  DHATUS_PART_4,
  DHATUS_PATCH,
  DHATUS_EXTRA,
);
